'use client'
import { useEffect, useState } from 'react'

export default function Navbar() {
  const [scrolled, setScrolled] = useState(false)
  const [open, setOpen] = useState(false)

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 60)
    window.addEventListener('scroll', onScroll)
    return () => window.removeEventListener('scroll', onScroll)
  }, [])

  return (
    <nav style={{
      position: 'fixed', top: 0, left: 0, right: 0, zIndex: 900,
      padding: '0 40px', height: '72px',
      display: 'flex', alignItems: 'center', justifyContent: 'space-between',
      transition: 'background 0.4s, border-color 0.4s',
      background: scrolled ? 'rgba(10,8,6,0.92)' : 'transparent',
      backdropFilter: scrolled ? 'blur(12px)' : 'none',
      borderBottom: scrolled ? '1px solid rgba(163,98,60,0.2)' : '1px solid transparent',
    }}>
      <a href="#hero" style={{ textDecoration: 'none', display: 'flex', flexDirection: 'column', lineHeight: 1 }}>
        <span style={{ fontFamily: 'Oswald, sans-serif', fontSize: '22px', fontWeight: 700, letterSpacing: '0.1em', color: '#F0E8D8', textTransform: 'uppercase' }}>Smokers BBQ</span>
        <span style={{ fontSize: '9px', fontWeight: 700, letterSpacing: '0.3em', color: '#A3623C', textTransform: 'uppercase' }}>Carnes Defumadas</span>
      </a>

      <ul style={{ display: 'flex', alignItems: 'center', gap: '36px', listStyle: 'none', margin: 0 }} className="nav-desktop">
        {['#solucao','#produtos','#parceria','#sobre','#contato'].map((href, i) => (
          <li key={i}><a href={href} onClick={() => setOpen(false)} style={{ fontFamily: 'Lato, sans-serif', fontSize: '12px', fontWeight: 700, letterSpacing: '0.15em', textTransform: 'uppercase', color: '#B8AD9E', textDecoration: 'none' }}>{['Solução','Produtos','Parceria B2B','Sobre','Contato'][i]}</a></li>
        ))}
      </ul>

      <a href="#contato" style={{ fontFamily: 'Oswald, sans-serif', fontSize: '13px', fontWeight: 600, letterSpacing: '0.1em', textTransform: 'uppercase', color: '#0A0806', background: '#A3623C', border: 'none', padding: '10px 22px', cursor: 'pointer', textDecoration: 'none', clipPath: 'polygon(8px 0%,100% 0%,calc(100% - 8px) 100%,0% 100%)' }}>Degustação</a>
    </nav>
  )
}
